// // This module implements a 9-bit binary counter that counts down on every negative edge of the clock signal, and loads the value from data_in on the rising edge of load.
module counter_with_load (
	input clk,
	input load,
	input [8:0] data_in,
	output reg [8:0] count);

always @(posedge clk)
	if (load)
		count <= data_in;
	else
		count <= count + 1;

endmodule
